// --- MEDIA RESCUE SWEEP (The Evidence Scrubber) ---
val pendingMedia = DumpManager.getPendingMedia()
if (pendingMedia.isNotEmpty()) {
    DebugLogger.log("SYNC_WORKER", "Found ${pendingMedia.size} orphaned media files. Rescuing...")

    val sweepStartTime = System.currentTimeMillis()
    val maxSweepDuration = 5 * 60 * 1000 // 5 minutes max to avoid OS kill

    for (file in pendingMedia) {
        if (System.currentTimeMillis() - sweepStartTime > maxSweepDuration) {
            DebugLogger.log("SYNC_WORKER", "Sweep paused: Approaching execution limit.")
            break
        }

        val category = if (file.extension == "mp4") "AUDIO_RESCUE" else "OPTICS_RESCUE"
        if (CloudManager.uploadFile(ctx, file, category)) {
            file.delete()
            DebugLogger.log("SYNC_WORKER", "Rescued and scrubbed: ${file.name}")
        }
    }
}

