2310 |     // --- CLIENT SIDE PATCH ENGINE (Smart Line-Matcher) ---
2311 |     function applyLocalPatch(content, ops) {
2312 |         let lines = content.split('\n');
2313 |         let logs = [];
2314 |         let success = true;
2315 | 
2316 |         if (typeof ops === 'string') {
2317 |             try { ops = JSON.parse(ops); } catch(e) { return { content, success: false, logs: ["Invalid JSON"]}; }
2318 |         }
2319 | 
2320 |         ops.forEach(op => {
2321 |             if (op.action === 'comment') return;
2322 |             if (op.action === 'create_file') { lines = op.content.split('\n'); logs.push('Created file'); return; }
2323 |             
2324 |             if (op.action === 'replace_block') {
2325 |                 // Strategy 1: Exact String Match (Fastest)
2326 |                 const currentStr = lines.join('\n');
2327 |                 if (currentStr.includes(op.find_block)) {
2328 |                     lines = currentStr.replace(op.find_block, op.replace_with).split('\n');
2329 |                     logs.push('Exact match applied');
2330 |                     return;
2331 |                 }
2332 | 
2333 |                 // Strategy 2: Line-by-Line Fuzzy Match (Whitespace Agnostic)
2334 |                 const searchLines = op.find_block.split('\n').map(l => l.trim()).filter(l => l !== '');
2335 |                 if (searchLines.length === 0) return;
2336 | 
2337 |                 let matchStart = -1;
2338 |                 let matchEnd = -1;
2339 | 
2340 |                 // Scan file lines
2341 |                 for (let i = 0; i < lines.length; i++) {
2342 |                     // If first line matches (ignoring whitespace)
2343 |                     if (lines[i].trim() === searchLines[0]) {
2344 |                         // Check subsequent lines
2345 |                         let allMatch = true;
2346 |                         let fileOffset = 0;
2347 |                         let searchOffset = 1;
2348 |                         
2349 |                         while (searchOffset < searchLines.length) {
2350 |                             if (i + fileOffset + 1 >= lines.length) { allMatch = false; break; }
2351 |                             const nextFile = lines[i + fileOffset + 1].trim();
2352 |                             // Skip empty lines in file if they aren't in search block
2353 |                             if (nextFile === '') {
2354 |                                 fileOffset++;
2355 |                                 continue;
2356 |                             }
2357 |                             if (nextFile !== searchLines[searchOffset]) {
2358 |                                 allMatch = false;
2359 |                                 break;
2360 |                             }
2361 |                             fileOffset++;
2362 |                             searchOffset++;
2363 |                         }
2364 | 
2365 |                         if (allMatch) {
2366 |                             matchStart = i;
2367 |                             matchEnd = i + fileOffset;
2368 |                             break;
2369 |                         }
2370 |                     }
2371 |                 }
2372 | 
2373 |                 if (matchStart !== -1) {
2374 |                     // Replace the range of lines
2375 |                     const replacement = op.replace_with.split('\n');
2376 |                     lines.splice(matchStart, (matchEnd - matchStart) + 1, ...replacement);
2377 |                     logs.push(`Fuzzy match applied (Lines ${matchStart+1}-${matchEnd+1})`);
2378 |                 } else {
2379 |                     success = false;
2380 |                     logs.push(`Failed to find block: "${op.find_block.substring(0, 30)}..."`);
2381 |                     console.warn("Patch Mismatch. File has:", content.substring(0, 200), "... vs Search:", op.find_block);
2382 |                 }
2383 |             }
2384 |         });
2385 |         return { content: lines.join('\n'), success, logs };
2386 |     }
