5371 |     // --- GENERIC UI ---
5372 |     function formatBytes(bytes) {
5373 |         if (!bytes) return '0 B';
5374 |         const k = 1024;
5375 |         const sizes = ['B', 'KB', 'MB', 'GB'];
5376 |         const i = Math.floor(Math.log(bytes) / Math.log(k));
5377 |         return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];
5378 |     }
