5380 |     function timeAgo(dateString) {
5381 |         const date = new Date(dateString);
5382 |         const now = new Date();
5383 |         const seconds = Math.floor((now - date) / 1000);
5384 |         if (seconds < 10) return 'just now';
5385 |         if (seconds < 60) return seconds + 's ago';
5386 |         const minutes = Math.floor(seconds / 60);
5387 |         if (minutes < 60) return minutes + 'm ago';
5388 |         const hours = Math.floor(minutes / 60);
5389 |         if (hours < 24) return hours + 'h ago';
5390 |         return date.toLocaleDateString();
5391 |     }
