5619 | 
5620 |         const attemptNavigation = async () => {
5621 |             const element = document.querySelector(selector);
5622 |             
5623 |             if (element) {
5624 |                 console.log("[DeepJump] Element found. Scrolling...");
5625 |                 
5626 |                 // Wait for any tab transition animations
5627 |                 await new Promise(r => setTimeout(r, 300));
5628 | 
5629 |                 let offsetTop = 0;
5630 |                 let curr = element;
5631 |                 while (curr && curr !== scrollContainer) {
5632 |                     offsetTop += curr.offsetTop;
5633 |                     curr = curr.offsetParent;
5634 |                 }
5635 | 
5636 |                 const targetScroll = offsetTop - (scrollContainer.clientHeight / 2) + (element.clientHeight / 2);
5637 |                 scrollContainer.scrollTo({ top: targetScroll, behavior: 'smooth' });
5638 | 
5639 |                 // Visual Highlight
