5646 |                 }, 3000);
5647 |                 
5648 |                 console.groupEnd();
5649 |                 return true;
5650 |             }
5651 | 
5652 |             if (retryCount < MAX_RETRIES && loadMoreFn) {
5653 |                 console.log(`[DeepJump] Not found. Triggering loadMore (Attempt ${retryCount + 1})...`);
5654 |                 retryCount++;
5655 |                 showGlobalToast("🔍 Searching deeper...");
5656 |                 
5657 |                 await loadMoreFn(); 
5658 |                 await new Promise(r => setTimeout(r, 800)); // Wait for render
5659 |                 return attemptNavigation();
5660 |             }
5661 | 
5662 |             console.error("[DeepJump] Failed: Element not found after retries.");
5663 |             showGlobalToast("Entry not found in recent history.", true);
5664 |             console.groupEnd();
5665 |             return false;
5666 |         };
