8321 |     function extractTableNames(sql) {
8322 |         if (!sql) return [];
8323 |         const tables = [];
8324 |         const systemNoise = ['columns', 'tables', 'schemata', 'information_schema'];
8325 |         
8326 |         // Pattern 1: Standard FROM/JOIN (handles schema.table and "table")
8327 |         const fromRegex = /(?:FROM|JOIN)\s+(?:(?:"?\w+"?\.)?"?(\w+)"?)/gi;
8328 |         // Pattern 2: Metadata queries (WHERE table_name = '...')
8329 |         const metaRegex = /table_name\s*=\s*'([^']+)'/gi;
8330 | 
8331 |         let match;
8332 |         while ((match = fromRegex.exec(sql)) !== null) {
8333 |             const name = match[1];
8334 |             if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
8335 |                 tables.push(name);
8336 |             }
8337 |         }
8338 |         
8339 |         while ((match = metaRegex.exec(sql)) !== null) {
8340 |             const name = match[1];
8341 |             if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
8342 |                 tables.push(name);
8343 |             }
8344 |         }
8345 | 
8346 |         return tables;
8347 |     }
8348 | 
8349 |     function convertToCSV(resultObj) {
8350 |         const data = resultObj.data || [];
8351 |         if (!data.length) return '';
8352 |         
8353 |         const tables = extractTableNames(resultObj.sql);
8354 |         const metaHeader = tables.length > 0 ? `# Source Tables: ${tables.join(', ')}\n# Export Date: ${new Date().toISOString()}\n` : '';
8355 | 
8356 |         const headers = Object.keys(data[0]);
8357 |         const rows = data.map(row => 
8358 |             headers.map(header => {
8359 |                 let cell = row[header] === null || row[header] === undefined ? '' : row[header];
8360 |                 if (typeof cell === 'object') cell = JSON.stringify(cell);
8361 |                 return '"' + String(cell).replace(/"/g, '""') + '"';
8362 |             }).join(',')
8363 |         );
8364 |         return metaHeader + [headers.join(','), ...rows].join('\n');
8365 |     }
