let cicdSelectedIds = new Set();

ops.find_block:
async function deleteWorkflowRun(runId) {
    if (!confirm("Delete this run log from GitHub?")) return;
    try {
        const res = await fetch(CONFIG.funcUrl, {
            method: 'POST', headers: {'Content-Type': 'application/json'},
            body: apiBody({ action: 'delete_run', run_id: runId })
        });
        const data = await res.json();
        if (data.success) {
            showGlobalToast("Log deleted");
            loadWorkflows(true);
        } else throw new Error(data.error || "Failed to delete");
    } catch(e) { showGlobalToast(e.message, true); }
}

ops.replace_with:
function enterCicdSelectionMode(initialId) {
    cicdSelectionMode = true;
    cicdSelectedIds.clear();
    if (initialId) cicdSelectedIds.add(initialId);
    document.getElementById('cicd-actions-fab').style.display = 'flex';
    applyFiltersToCicd();
}

function exitCicdSelectionMode() {
    cicdSelectionMode = false;
    cicdSelectedIds.clear();
    document.getElementById('cicd-actions-fab').style.display = 'none';
    applyFiltersToCicd();
}

function toggleCicdRunSelection(id) {
    if (cicdSelectedIds.has(id)) cicdSelectedIds.delete(id);
    else cicdSelectedIds.add(id);
    applyFiltersToCicd();
}

async function deleteSelectedWorkflows() {
    const ids = Array.from(cicdSelectedIds);
    if (ids.length === 0) return;

    if (!confirm(`🗑️ DELETE WORKFLOWS\n\nThis will permanently remove ${ids.length} run logs from GitHub.\n\nContinue?`)) return;

    showGlobalToast(`Deleting ${ids.length} runs...`);

    try {
        await Promise.all(ids.map(id => 
            fetch(CONFIG.funcUrl, {
                method: 'POST', headers: {'Content-Type': 'application/json'},
                body: apiBody({ action: 'delete_run', run_id: id })
            })
        ));

        showGlobalToast("✅ Runs deleted successfully");
        exitCicdSelectionMode();
        loadWorkflows(true);
    } catch(e) {
        showGlobalToast("Error during batch deletion", true);
        loadWorkflows(true);
    }
}

